import { useEffect, useState } from "react";
import axios from "../api/axios";
import { useNavigate } from "react-router-dom";

export default function ParkingList() {
  const [lots, setLots] = useState([]);
  const navigate = useNavigate();

  useEffect(() => {
    console.log("Fetching parking lots...");
    axios.get("/parking")
      .then(res => {
        console.log("Got lots:", res.data);
        setLots(res.data);
      })
      .catch(err => {
        console.error("Error fetching lots:", err);
        alert("Failed to fetch parking lots. Check console/backend.");
      });
  }, []);

  return (
    <div className="container">
      <h2>Available Parking Lots</h2>
      <div className="grid">
        {lots.map(lot => (
          <div className="card" key={lot._id}>
            <h3>{lot.name}</h3>
            <p>{lot.location}</p>
            <button onClick={() => navigate(`/slots/${lot._id}`)}>View Slots</button>
          </div>
        ))}
      </div>
    </div>
  );
}
